/**
 * Lancer Sitrep Tracker — Small Semantic DSL
 *
 * This file compresses repetitive syntax only.
 * The primary feature file continues to own:
 * - configuration
 * - composition
 * - labels
 * - conditions
 * - domain rules
 * - state meaning
 * - action meaning
 */

import {
  escapeHTML
} from "./ui-boilerplate.js";

function contentOf(values) {
  return values
    .flat(Infinity)
    .filter(
      value =>
        value !== false &&
        value !== null &&
        value !== undefined
    )
    .join("");
}

function attributesOf(attributes = {}) {
  const rendered = Object.entries(attributes)
    .filter(
      ([, value]) =>
        value !== false &&
        value !== null &&
        value !== undefined &&
        value !== ""
    )
    .map(([key, value]) => {
      const name =
        key === "className"
          ? "class"
          : key;

      if (value === true) {
        return name;
      }

      return `${name}="${escapeHTML(value)}"`;
    });

  return rendered.length
    ? ` ${rendered.join(" ")}`
    : "";
}

export function html(
  tag,
  attributes = {},
  ...children
) {
  return `<${tag}${attributesOf(attributes)}>${contentOf(children)}</${tag}>`;
}

export function emptyTag(
  tag,
  attributes = {}
) {
  return `<${tag}${attributesOf(attributes)}>`;
}

export function fragment(...children) {
  return contentOf(children);
}

export function when(
  condition,
  content
) {
  if (!condition) return "";

  return typeof content === "function"
    ? content()
    : content;
}

export function each(
  values,
  render
) {
  return (values ?? [])
    .map(render)
    .join("");
}

export function div(
  className,
  ...children
) {
  return html(
    "div",
    { class: className },
    ...children
  );
}

export function span(
  text,
  className = ""
) {
  return html(
    "span",
    { class: className },
    text
  );
}

export function strong(text) {
  return html(
    "strong",
    {},
    text
  );
}

export function small(text) {
  return html(
    "small",
    {},
    text
  );
}

export function icon(className) {
  return html(
    "i",
    { class: className }
  );
}

export function actionButton(
  action,
  label,
  {
    className = "",
    disabled = false,
    title = "",
    ariaLabel = "",
    data = {},
    iconClass = ""
  } = {}
) {
  const dataAttributes = Object.fromEntries(
    Object.entries(data).map(
      ([key, value]) => [
        `data-${key}`,
        value
      ]
    )
  );

  return html(
    "button",
    {
      type: "button",
      class: className,
      "data-action": action,
      disabled,
      title,
      "aria-label": ariaLabel,
      ...dataAttributes
    },
    iconClass ? icon(iconClass) : "",
    label
  );
}

export function stat(
  label,
  value,
  className
) {
  return div(
    className,
    span(label),
    strong(value)
  );
}

export function statusBlock(
  className,
  text
) {
  return div(
    className,
    text
  );
}

export function labeledValue(
  className,
  label,
  value
) {
  return div(
    className,
    span(label),
    strong(value)
  );
}

export function option(
  value,
  label,
  selected = false
) {
  return html(
    "option",
    {
      value,
      selected
    },
    escapeHTML(label)
  );
}

export function options(
  values,
  {
    selected = [],
    valueOf = item => item?.id,
    labelOf = item => item?.name ?? item?.id
  } = {}
) {
  const selectedValues = new Set(
    Array.isArray(selected)
      ? selected.map(String)
      : [String(selected ?? "")]
  );

  return each(values, item => {
    const value = String(
      valueOf(item) ?? ""
    );

    return option(
      value,
      labelOf(item),
      selectedValues.has(value)
    );
  });
}

export function formGroup(
  label,
  control,
  {
    className = "form-group",
    notes = "",
    style = ""
  } = {}
) {
  return div(
    className,
    html("label", {}, label),
    control,
    when(
      notes,
      html(
        "p",
        { class: "notes" },
        notes
      )
    )
  ).replace(
    `<div class="${className}">`,
    `<div${attributesOf({
      class: className,
      style
    })}>`
  );
}

export function selectControl(
  name,
  optionMarkup,
  {
    multiple = false,
    size = null
  } = {}
) {
  return html(
    "select",
    {
      name,
      multiple,
      size
    },
    optionMarkup
  );
}

export function inputControl(
  name,
  {
    type = "text",
    value = "",
    min = null,
    max = null,
    checked = false
  } = {}
) {
  return emptyTag(
    "input",
    {
      type,
      name,
      value,
      min,
      max,
      checked
    }
  );
}

export function textareaControl(
  name,
  value,
  rows = 3
) {
  return html(
    "textarea",
    {
      name,
      rows
    },
    escapeHTML(value)
  );
}

export function chatResult(
  title,
  lines = [],
  className = ""
) {
  return div(
    ["lst-chat-result", className]
      .filter(Boolean)
      .join(" "),
    strong(title),
    each(
      lines,
      line => `<br>${line}`
    )
  );
}

