function progressPips(sitrep, state) {
  const total = Math.max(
    Number(sitrep.roundLimit ?? 8),
    1
  );


  const remaining = Math.min(
    Math.max(state.roundsRemaining, 0),
    total
  );


  return Array.from(
    { length: total },
    (_, index) =>
      `<span class="lst-pip ${
        index < remaining ? "filled" : ""
      }"></span>`
  ).join("");
}

